/**
 * Isolates the factorized-tail aggregation path on pure star joins: hubs fanning out over two predicates, aggregated
 * with COUNT and exact SUM variants whose tail matches are consumed as batches. Run twice — once as-is and once with
 * {@code -Drdf4j.lmdb.factorizedTail.enabled=false} — to compare against the enumerating baseline. Each invocation
 * verifies the expected count, so a wrong factorized result fails the run. The {@code sumHubValue} setup also verifies
 * that the enabled run uses the chunk-prefix factorized tail and that the disabled control does not.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 4, time = 2, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 3, jvmArgs = { "-Xms1G", "-Xmx4G" })
@Measurement(iterations = 4, batchSize = 1, time = 2, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class FactorizedTailStarBenchmark {

	private static final String EX = "http://example.com/";
	private static final int HUBS = 1_000;
	private static final int P1_FANOUT = 10;
	private static final int P2_FANOUT = 100;
	private static final int P2_DISTINCT_VALUES = 500;
	private static final String FACTORIZED_TAIL_FLAG = "rdf4j.lmdb.factorizedTail.enabled";
	private static final String PARALLEL_FLAG = "rdf4j.lmdb.parallel.enabled";

	@Param({
			"countHub",
			"countDistinctHub",
			"countTail",
			"countDistinctTail",
			"groupByTail",
			"sumHubValue"
	})
	public String variant;

	private java.io.File dataDir;
	private SailRepository repository;
	private String query;
	private long expected;

	@Setup(Level.Trial)
	public void setUp() {
		// This benchmark isolates serial factorized-tail execution; parallel aggregation has its own benchmark.
		System.setProperty(PARALLEL_FLAG, "false");
		dataDir = Files.newTemporaryFolder();
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			conn.begin();
			IRI pn = vf.createIRI(EX, "pn");
			for (int hub = 0; hub < HUBS; hub++) {
				IRI subject = vf.createIRI(EX, "hub" + hub);
				// one numeric per hub: SUM(?n) over the star = Σ hub × (P1_FANOUT × P2_FANOUT)
				conn.add(subject, pn, vf.createLiteral(hub));
				for (int i = 0; i < P1_FANOUT; i++) {
					conn.add(subject, p1, vf.createIRI(EX, "a" + (hub * P1_FANOUT + i)));
				}
				for (int i = 0; i < P2_FANOUT; i++) {
					conn.add(subject, p2, vf.createIRI(EX, "b" + ((hub * P2_FANOUT + i) % P2_DISTINCT_VALUES)));
				}
			}
			conn.commit();
		}
		long solutions = (long) HUBS * P1_FANOUT * P2_FANOUT;
		switch (variant) {
		case "countHub":
			query = star("(COUNT(?s) AS ?count)", "");
			expected = solutions;
			break;
		case "countDistinctHub":
			query = star("(COUNT(DISTINCT ?s) AS ?count)", "");
			expected = HUBS;
			break;
		case "countTail":
			query = star("(COUNT(?b) AS ?count)", "");
			expected = solutions;
			break;
		case "countDistinctTail":
			query = star("(COUNT(DISTINCT ?b) AS ?count)", "");
			expected = P2_DISTINCT_VALUES;
			break;
		case "groupByTail":
			query = star("?b (COUNT(?s) AS ?count)", "") + " GROUP BY ?b";
			// per group: (HUBS * P2_FANOUT / P2_DISTINCT_VALUES) hub-matches x P1_FANOUT
			expected = (long) HUBS * P2_FANOUT / P2_DISTINCT_VALUES * P1_FANOUT;
			break;
		case "sumHubValue":
			// Phase 3: value-typed aggregate over a prefix slot with two counting branches — the sum
			// contribution per hub is value × product of branch counts instead of per-row addition
			query = "PREFIX ex: <" + EX + ">\n"
					+ "SELECT (SUM(?n) AS ?count) WHERE {\n"
					+ "  ?s ex:pn ?n .\n"
					+ "  ?s ex:p1 ?a .\n"
					+ "  ?s ex:p2 ?b .\n"
					+ "}";
			expected = (long) HUBS * (HUBS - 1) / 2 * P1_FANOUT * P2_FANOUT;
			break;
		default:
			throw new IllegalArgumentException(variant);
		}
		if ("sumHubValue".equals(variant)) {
			executeQuery();
			verifySumHubValueStrategy();
		}
	}

	private static String star(String select, String extra) {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT " + select + " WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ extra
				+ "}";
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		try {
			repository.shutDown();
			FileUtil.deleteDir(dataDir);
		} finally {
			System.clearProperty(PARALLEL_FLAG);
		}
	}

	private void verifySumHubValueStrategy() {
		String actual = strategy();
		boolean factorizedEnabled = !"false".equals(System.getProperty(FACTORIZED_TAIL_FLAG));
		if (factorizedEnabled && !actual.startsWith("factorizedTail(prefix=chunkPipeline,")) {
			throw new IllegalStateException(
					"sumHubValue: expected chunk-prefix factorized tail but got " + actual);
		}
		if (!factorizedEnabled && actual.startsWith("factorizedTail")) {
			throw new IllegalStateException(
					"sumHubValue: disabled control unexpectedly used " + actual);
		}
	}

	private String strategy() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			GenericPlanNode plan = connection.prepareTupleQuery(query)
					.explain(Explanation.Level.Telemetry)
					.toGenericPlanNode();
			String strategy = findStrategy(plan);
			if (strategy == null) {
				throw new IllegalStateException("sumHubValue: explanation did not report nativeExecutionPath");
			}
			return strategy;
		}
	}

	private static String findStrategy(GenericPlanNode node) {
		if (node == null) {
			return null;
		}
		String strategy = node.getStringMetricActual("nativeExecutionPath");
		if (strategy != null) {
			return strategy;
		}
		if (node.getPlans() != null) {
			for (GenericPlanNode child : node.getPlans()) {
				String found = findStrategy(child);
				if (found != null) {
					return found;
				}
			}
		}
		return null;
	}

	@Benchmark
	public long executeQuery() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			long total = 0;
			for (BindingSet bindings : result) {
				long count = ((Literal) bindings.getValue("count")).longValue();
				if (!"groupByTail".equals(variant) && count != expected) {
					throw new IllegalStateException(variant + ": expected " + expected + " but got " + count);
				}
				if ("groupByTail".equals(variant) && count != expected) {
					throw new IllegalStateException(variant + ": expected " + expected + " per group but got " + count);
				}
				total += count;
			}
			if ("groupByTail".equals(variant) && result.size() != P2_DISTINCT_VALUES) {
				throw new IllegalStateException("groupByTail: expected " + P2_DISTINCT_VALUES + " groups but got "
						+ result.size());
			}
			return total;
		}
	}

	public static void main(String[] args) throws RunnerException {
		Options opt = new OptionsBuilder()
				.include("FactorizedTailStarBenchmark")
				.build();
		new Runner(opt).run();
	}
}
